/* alinnman published fixes: raw sextant altitude (Hs) per sight;
 * the check runs our standard-atmosphere correction chain (eye=0,
 * ie=0, limb=0, T=10 C, P=1010 mb -- exactly the corrections
 * their Sight() applied: Bennett refraction, no dip, central
 * limb) then our n-body fix. body: star index, -1 = Sun, -2 =
 * Moon. For a Moon row the C side supplies OUR ephemeris HP at
 * the instant (their Sight() looked HP up from its almanac at
 * the sight hour), so the raw sight exercises refraction + lunar
 * parallax end to end through the Moon correction chain. */
typedef struct {
    int64_t ut1_ms;
    int32_t tt_minus_ut1_ms;
    int32_t body;          /* star index, -1 = Sun, -2 = Moon */
    int64_t hs_marcmin;    /* raw sextant altitude */
} alinnman_sight_t;

