/* rgleason INTERCEPT_SIGHTS: a full Sun sight line. hs_marcmin the
 * raw sextant altitude; ie_marcmin NEGATIVE because their chain
 * subtracts the index error (Ha = Hs - IE - dip) while ours adds
 * it. gha/dec baked into their published Sun direction (Q2.30)
 * for the ephemeris and reduction gates. ho/hc are their published
 * observed and computed altitudes; zn their azimuth; intercept in
 * tenths of a nautical mile, POSITIVE toward. All rows: T=10 C,
 * P=1010 mb, index error 1.5', eye 3.5 m. */
typedef struct {
    int64_t ut1_ms;
    int32_t tt_minus_ut1_ms;
    int32_t limb;             /* +1 lower, -1 upper */
    int32_t temp_c, pressure_mb;
    int64_t ie_marcmin;       /* signed; negative (their convention) */
    int32_t eye_cm;
    int64_t hs_marcmin;
    int64_t ho_marcmin;       /* their published Ho */
    int32_t bx, by, bz;       /* their Sun direction, Q2.30 */
    int32_t dr_lat_cdeg, dr_lon_cdeg;
    int64_t hc_marcmin;       /* their published Hc */
    int32_t zn_cdeg;          /* their published azimuth */
    int32_t intercept_tenths_nm; /* signed; + toward */
} intercept_row_t;

